+}
+
+arithmeticForm?.addEventListener("submit", (event) => {
+  event.preventDefault();
+  computeArithmetic();
+});
+
+functionForm?.addEventListener("submit", (event) => {
+  event.preventDefault();
+  computeFunction();
+});
