+  updatePowerVisibility();
+  computeArithmetic();
+});
+for (const input of [xInput, seedInput]) input?.addEventListener("input", computeFunction);
+functionInput?.addEventListener("change", computeFunction);
+
+updatePowerVisibility();
+computeArithmetic();
+computeFunction();

